            // Optimization: Set connection and read timeouts
            connection.setConnectTimeout(TIMEOUT_CONNECT);
            connection.setReadTimeout(TIMEOUT_READ);

            // Optimization/Fix: Set User-Agent to avoid 403 Forbidden errors from some servers
            connection.setRequestProperty("User-Agent", "Mozilla/5.0 (compatible; ImageService/1.0)");

